import React, { useState } from 'react';
import './App.css';
import Header from './components/Header';
import GeneratorForm from './components/GeneratorForm';
import NftPreview from './components/NftPreview';
import Footer from './components/Footer';

function App() {
  const [previewImage, setPreviewImage] = useState(null);

  // Handle the generation of NFT images
  const handleGenerate = (description, style) => {
    console.log(description, style);
    setPreviewImage('https://via.placeholder.com/600x400'); // Placeholder for generated image
  };

  return (
    <div className="App">
      <Header />
      <div className="main-content">
        <GeneratorForm onGenerate={handleGenerate} />
        {previewImage && <NftPreview previewImage={previewImage} />}
      </div>
      <Footer />
    </div>
  );
}

export default App;
